 1	import React, { useMemo } from 'react';
 2	import xbytes from 'xbytes';
 3	
 4	import useResponsiveCharts from '@kubevirt-utils/components/Charts/hooks/useResponsiveCharts';
 5	import DurationOption from '@kubevirt-utils/components/DurationOption/DurationOption';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { isEmpty } from '@kubevirt-utils/utils/utils';
 8	import { Bullseye, Divider, Grid, HelperText, HelperTextItem } from '@patternfly/react-core';
 9	
10	import MigrationsTimeAxis from './components/MigrationsTimeAxis';
11	import MigrationsUtilizationChart from './components/MigrationsUtilizationChart';
12	import useMigrationChartsData from './useMigrationChartsData';
13	import { getDomainY, getLabel, getTickValuesAxisY } from './utils';
14	
15	type BandwidthConsumptionChartsProps = {
16	  duration: string;
17	};
18	
19	const BandwidthConsumptionCharts: React.FC<BandwidthConsumptionChartsProps> = ({ duration }) => {
20	  const { t } = useKubevirtTranslation();
21	
22	  const currentTime = useMemo(() => Date.now(), []);
23	  const timespan = DurationOption.getMilliseconds(duration);
24	  const domainX: [number, number] = [currentTime - timespan, currentTime];
25	  const { ref } = useResponsiveCharts();
26	
27	  const { bandwidthConsumed, maxBandwidthConsumed, maxMigrationCount, migrationsCount } =
28	    useMigrationChartsData(duration, currentTime, timespan);
29	
30	  return (
31	    <div>
32	      {!isEmpty(bandwidthConsumed) || !isEmpty(migrationsCount) ? (
33	        <Grid ref={ref}>
34	          <MigrationsTimeAxis domainX={domainX} timespan={timespan} />
35	          <MigrationsUtilizationChart
36	            domain={{
37	              x: domainX,
38	              y: getDomainY(maxBandwidthConsumed),
39	            }}
40	            chartData={bandwidthConsumed}
41	            labels={getLabel(timespan, bandwidthConsumed, true)}
42	            tickFormat={(y) => xbytes(y, { fixed: 0, iec: true, prefixIndex: 3 })}
43	            tickValues={getTickValuesAxisY(maxBandwidthConsumed)}
44	            title={t('Network consumption')}
45	          />
46	          <Divider />
47	          <MigrationsUtilizationChart
48	            domain={{
49	              x: domainX,
50	              y: getDomainY(maxMigrationCount, 1),
51	            }}
52	            chartData={migrationsCount}
53	            labels={getLabel(timespan, migrationsCount)}
54	            tickValues={getTickValuesAxisY(maxMigrationCount, 1)}
55	            title={t('Running migrations')}
56	          />
57	        </Grid>
58	      ) : (
59	        <Bullseye>
60	          <HelperText>
61	            <HelperTextItem variant="warning">
62	              {t('No Datapoints found')}
63	            </HelperTextItem>
64	          </HelperText>
65	        </Bullseye>
66	      )}
67	    </div>
68	  );
69	};
70	
71	export default BandwidthConsumptionCharts;

